import React from 'react';
import ThanksSection from './Welcome/ThanksSection';
import AdvertisementCarousel from './Welcome/AdvertisementCarousel';
import ExternalLinksHomeSection from './ExternalLinks/ExternalLinksHomeSection';

const intl = getIntl();

type CardProps = {
  title: string;
  index: number;
  desc: string;
  href: string;
  internal?: boolean;
};

/**
 * 每个单独的卡片，为了复用样式抽成了组件
 * @param param0
 * @returns
 */
const InfoCard: React.FC<CardProps> = ({ title, href, index, desc, internal }) => {
  const { useToken } = theme;

  const { token } = useToken();

  const content = (
    <>
      <div style={{ display: 'flex', gap: '4px', alignItems: 'center' }}>
        <div
          style={{
            width: 48,
            height: 48,
            lineHeight: '22px',
            backgroundSize: '100%',
            textAlign: 'center',
            padding: '8px 16px 16px 12px',
            color: '#FFF',
            fontWeight: 'bold',
            backgroundImage:
              "url('https://gw.alipayobjects.com/zos/bmw-prod/daaf8d50-8e6d-4251-905d-676a24ddfa12.svg')",
          }}
        >
          {index}
        </div>
        <div style={{ fontSize: '16px', color: token.colorText, paddingBottom: 8 }}>{title}</div>
      </div>
      <div
        style={{
          fontSize: '14px',
          color: token.colorTextSecondary,
          textAlign: 'justify',
          lineHeight: '22px',
          marginBottom: 8,
        }}
      >
        {desc}
      </div>
      <span>
        <FormattedMessage id="home.learn_more" /> {'>'}
      </span>
    </>
  );

  return (
    <div
      style={{
        backgroundColor: token.colorBgContainer,
        boxShadow: token.boxShadow,
        borderRadius: '8px',
        fontSize: '14px',
        color: token.colorTextSecondary,
        lineHeight: '22px',
        padding: '16px 19px',
        minWidth: '220px',
        flex: 1,
      }}
    >
      {internal ? (
        <Link to={href} style={{ color: 'inherit', textDecoration: 'none' }}>
          {content}
        </Link>
      ) : (
        <a href={href} target="_blank" rel="noreferrer">
          {content}
        </a>
      )}
    </div>
  );
};

