            <Select mode="tags" placeholder="输入后回车" tokenSeparators={[',']} />
          </Form.Item>
          <Form.Item name="wechat_groups" label="微信群">
            <Select mode="tags" placeholder="输入后回车" tokenSeparators={[',']} />
          </Form.Item>
        </Form>
      </Modal>
    </PageContainer>
  );
};

