  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const text = reader.result as string;
      const result = importPracticeConfig(text);
      if (result.success) {
        message.success(intl.formatMessage({ id: 'algs.practiceConfig.importSuccess' }));
      } else {
        message.error(
          intl.formatMessage(
            { id: 'algs.practiceConfig.importFailed' },
            { msg: result.message ?? '' },
          ),
        );
      }
    };
    reader.readAsText(file, 'UTF-8');
    e.target.value = '';
  };

  useEffect(() => {
    getAlgCubeMap()
      .then(setData)
      .finally(() => setLoading(false));
  }, []);

  const cubeKeys = data?.CubeKeys ?? [];
  const classMap = data?.ClassMap ?? {};

  const filteredCubes = filterCube ? [filterCube] : cubeKeys;

  const handleCardClick = (cube: string, cls: OutputClass) => {
    navigate(`/algs/${encodeURIComponent(cube)}/${encodeURIComponent(cls.name)}`);
  };

  if (loading) {
    return (
      <div style={{ padding: 48, textAlign: 'center' }}>
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="algs-page-container" style={{ padding: '16px 0' }}>
      <h2 style={{ marginBottom: 16, color: 'rgba(0,0,0,0.85)' }}>
        {intl.formatMessage({ id: 'algs.title' })}
      </h2>
      {loggedIn ? (
        <UserCloudKvPanel
          kvKey={USER_KV_KEYS.algorithm_config}
          title={intl.formatMessage({ id: 'algs.cloud.title' })}
          description={intl.formatMessage({ id: 'algs.cloud.desc' })}
          uploadButtonText={intl.formatMessage({ id: 'algs.cloud.upload' })}
          syncButtonText={intl.formatMessage({ id: 'algs.cloud.sync' })}
          uploadOkText={intl.formatMessage({ id: 'algs.cloud.uploadOk' })}
          syncOkText={intl.formatMessage({ id: 'algs.cloud.syncOk' })}
          getPayloadForUpload={() => {
            const raw = JSON.stringify(exportPracticeConfig(), null, 2);
            assertPayloadWithinLimit(raw);
            return raw;
          }}
          applyCloudPayload={(raw) => {
            const result = importPracticeConfig(raw);
            if (!result.success) {
              throw new Error(result.message ?? 'import failed');
            }
          }}
        />
      ) : null}
      <div style={{ marginBottom: 16, display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 12 }}>
        <Select
          placeholder={intl.formatMessage({ id: 'algs.filter.placeholder' })}
          allowClear
          style={{ minWidth: 180 }}
          value={filterCube}
          onChange={(v) => setFilterCube(v ?? '')}
          options={[
            { value: '', label: intl.formatMessage({ id: 'algs.filter.all' }) },
            ...cubeKeys.map((c) => ({ value: c, label: c })),
          ]}
        />
        <Button
          icon={<DownloadOutlined />}
          onClick={handleExport}
          size="small"
        >
          {intl.formatMessage({ id: 'algs.practiceConfig.export' })}
        </Button>
        <Button
          icon={<UploadOutlined />}
          onClick={handleImport}
          size="small"
        >
          {intl.formatMessage({ id: 'algs.practiceConfig.import' })}
        </Button>
        <input
          ref={fileInputRef}
          type="file"
          accept=".json,application/json"
          style={{ display: 'none' }}
          onChange={handleFileChange}
        />
      </div>

      <Row gutter={[16, 16]} style={{ marginBottom: 32 }}>
        <Col xs={24} sm={12} md={8} lg={6} xl={6}>
          <Card
            hoverable
            onClick={() => setRandomPickModalOpen(true)}
            style={{
              borderRadius: 12,
              backgroundColor: ALGS_COLORS.cardBg,
              borderColor: ALGS_COLORS.cardBorder,
              overflow: 'hidden',
              animation: 'algsFloat 3s ease-in-out infinite',
              minHeight: 120,
            }}
            bodyStyle={{ padding: 20 }}
          >
            <div style={{ textAlign: 'center' }}>
              <SvgRenderer
                svg={RANDOM_PICK_ICON_SVG}
                maxWidth={100}
                maxHeight={100}
                style={{ marginTop: 24, marginBottom: 28 }}
              />
              <div style={{ fontWeight: 600, color: 'rgba(0,0,0,0.85)' }}>
                {intl.formatMessage({ id: 'algs.randomPick.title' })}
              </div>
            </div>
          </Card>
        </Col>
      </Row>

      {filteredCubes.flatMap((c) => classMap[c] ?? []).length === 0 ? (
        <Empty description={intl.formatMessage({ id: 'algs.empty' })} />
      ) : (
        <>
        <RandomPickModal
          open={randomPickModalOpen}
          onClose={() => setRandomPickModalOpen(false)}
          classMap={classMap}
          cubeKeys={filteredCubes}
        />
        {filteredCubes
          .filter((cube) => (classMap[cube] ?? []).length > 0)
          .map((cube) => {
            const classes = classMap[cube] ?? [];
            return (
            <div key={cube} style={{ marginBottom: 32 }}>
              <Divider
                orientation="left"
                style={{
                  borderColor: ALGS_COLORS.cardBorder,
                  fontSize: 16,
                  fontWeight: 600,
                  color: 'rgba(0,0,0,0.85)',
                }}
              >
                {cube}
              </Divider>
              <Row gutter={[16, 16]}>
                {classes.map((cls) => (
                  <Col key={`${cube}-${cls.name}`} xs={24} sm={12} md={8} lg={6} xl={6}>
                    <Card
                      hoverable
                      onClick={() => handleCardClick(cube, cls)}
                      style={{
                        borderRadius: 12,
                        backgroundColor: ALGS_COLORS.cardBg,
                        borderColor: ALGS_COLORS.cardBorder,
                        overflow: 'hidden',
                        animation: 'algsFloat 3s ease-in-out infinite',
                        minHeight: 120,
                      }}
                      bodyStyle={{ padding: 20 }}
                    >
                      <div style={{ textAlign: 'center' }}>
                        <SvgRenderer
                          svg={cls.image}
                          maxWidth={180}
                          maxHeight={260}
                          style={{ marginTop: 24, marginBottom: 28 }}
                        />
                        <div style={{ fontWeight: 600, color: 'rgba(0,0,0,0.85)' }}>{cls.name}</div>
                      </div>
                    </Card>
                  </Col>
                ))}
              </Row>
            </div>
            );
          })}
        </>
      )}
    </div>
  );
};

export default AlgsList;

