          }}
        >
          {isFav ? (
            <HeartFilled style={{ color: '#ff4d4f', fontSize: 18 }} />
          ) : (
            <HeartOutlined style={{ color: token.colorTextSecondary, fontSize: 18 }} />
          )}
        </div>
        {coverImg ? (
          <div className="recipe-card-cover" style={{ flexShrink: 0 }}>
            <img
