  const [data, setData] = useState<KitchenTipsData | null>(null);
  const [loading, setLoading] = useState(true);
  const [filterCategory, setFilterCategory] = useState<string>('');

  useEffect(() => {
    fetch(TIPS_JSON)
      .then((r) => r.json())
      .then(setData)
